Patching the loaded snake widget for smooth caterpillar-like movement.
_____javascript
const widget = space.chat.transient.get("snake-game");
if (!widget) throw new Error('snake-game widget not in transient');
const text = widget.text ?? widget.source ?? widget.content ?? widget.code ?? '';
const src = String(text);

const patched = (() => {
  const s = src;

  if (s.includes('smoothStep')) return s;

  const insertHelper = `
const CELL_ANIM_MS = 120;
const now = () => performance.now();
const clamp01 = (n) => Math.max(0, Math.min(1, n));
const easeOutCubic = (t) => 1 - Math.pow(1 - t, 3);
function lerp(a, b, t) { return a + (b - a) * t; }
`;

  let out = s;

  const snakeMatch = out.match(/(class\s+Snake[\s\S]*?)(class\s+Game|function\s+Game|const\s+Game|let\s+Game|export\s)/);
  if (snakeMatch && !out.includes('CELL_ANIM_MS')) {
    out = out.replace(snakeMatch[1], snakeMatch[1] + '\n' + insertHelper.trim() + '\n');
  }

  out = out.replace(
    /this\.segments\s*=\s*\[.*?\];/s,
    match => match + '\n    this.visualSegments = this.segments.map(p => ({ x: p.x, y: p.y }));\n    this.moveStart = now();\n    this.prevHead = { ...this.head };'
  );

  out = out.replace(
    /move\(\)\s*\{([\s\S]*?)\n\s*\}/,
    (m, body) => {
      if (body.includes('moveStart')) return m;
      return `move() {${body}
    this.prevHead = { ...this.head };
    const moved = this._moveCore ? this._moveCore() : null;
    this.moveStart = now();
    return moved;
  }`;
    }
  );

  if (!out.includes('_moveCore')) {
    out = out.replace(
      /move\(\)\s*\{[\s\S]*?\n\s*\}/,
      match => {
        const inner = match.replace(/^move\(\)\s*\{|\n\s*\}$/g, '');
        return `move() {
    this.prevHead = { ...this.head };
    const moved = this._moveCore();
    this.moveStart = now();
    return moved;
  }

  _moveCore() {${inner.replace(/^\n?/, '\n')}
  }`;
      }
    );
  }

  out = out.replace(
    /draw\(([^)]*)\)\s*\{([\s\S]*?)\n\s*\}/,
    (m, args, body) => {
      if (body.includes('visualSegments')) return m;
      return `draw(${args}) {${body}
    const t = clamp01((now() - this.moveStart) / CELL_ANIM_MS);
    const et = easeOutCubic(t);
    if (this.visualSegments && this.visualSegments.length) {
      for (let i = this.visualSegments.length - 1; i > 0; i--) {
        this.visualSegments[i].x = this.segments[i].x;
        this.visualSegments[i].y = this.segments[i].y;
      }
      if (this.prevHead && this.segments[0]) {
        this.visualSegments[0].x = lerp(this.prevHead.x, this.segments[0].x, et);
        this.visualSegments[0].y = lerp(this.prevHead.y, this.segments[0].y, et);
      }
    }
  }`;
    }
  );

  out = out.replace(
    /const\s+head\s*=\s*this\.segments\[0\];/g,
    'const head = (this.visualSegments && this.visualSegments[0]) || this.segments[0];'
  );

  out = out.replace(
    /const\s+segment\s*=\s*this\.segments\[i\];/g,
    'const segment = (this.visualSegments && this.visualSegments[i]) || this.segments[i];'
  );

  return out;
})();

if (patched === src) throw new Error('No patch was applied; source pattern not found.');
return await space.current.patchWidget("snake-game", { edits: [{ from: src, to: patched }] })

