  .replace(/move\s*[:=]\s*['"]?instant['"]?/gi, "move: 'smooth'")
  .replace(/transition\s*[:=]\s*['"]?none['"]?/gi, "transition: 'transform 120ms linear'")
  .replace(/animation\s*[:=]\s*['"]?none['"]?/gi, "animation: 'move 120ms linear'")
