const widget = await space.current.readWidget("snake-game");
const text = widget?.content ?? widget?.source ?? widget?.code ?? widget?.text ?? String(widget);

const replacements = [
  ['#0f380f', '#9bbc0f'],
  ['#306230', '#8bac0f'],
  ['#8bac0f', '#9bbc0f'],
