    patched = patched.replace(/background[^;\n]*[:=][^;\n]+/i, (m) => m.replace(/#[0-9a-fA-F]{3,6}\b|green|lime/i, '#9bbc0f'));
  }
}

return await space.current.patchWidget("snake-game", { edits: [{ oldText: text, newText: patched }] });

